def process_student_grades(students):
    results = []
    for student in students:
        total = 0
        count = 0
        for subject, grade in student['grades'].items():
            if grade is not None:
                total += grade
                count += 1
        if count > 0:
            average = total / count
        else:
            average = 0
        if average >= 60:
            status = 'passed'
        else:
            status = 'failed'
        results.append({'name': student['name'], 'average': average, 'status': status})
    return results

